  return {
    ...configuration,
    amountPresets: configuration?.amountPresets
      ? Object.keys(configuration?.amountPresets).reduce(
          (acc, nextPreset) => {
            const presets = configuration.amountPresets![nextPreset as AmountPresetFrequency];

            if (presets) {
              return {
                ...acc,
                [nextPreset]: presets.map((preset) => ({
                  ...preset,
                  amount: preset.amount ? currency(preset.amount).intValue : 0,
                })),
              };
            }

            return acc;
          },
          {} as Record<AmountPresetFrequency, ActionPageAmountPreset[]>
        )
      : undefined,
    futurePledgeDate: configuration.futurePledgeDate
